request.query:
prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?gateway ?gatewayName ?gatewayDirection ?type WHERE {
  ?gateway a bboExt:ParallelGateway .
  ?gateway tai:belongsTo <https://www.teamingai-project.eu/kg/process/qualityInspection/sid_628f8db4_6e66_4dbc_bf51_0a06087845fd> .
  OPTIONAL { ?gateway bbo:name ?gatewayName . }
  OPTIONAL { ?gateway bboExt:gatewayDirection ?gatewayDirection . }
  ?gateway a ?type .
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?elem ?elemName ?type ?loopType ?gatewayDir WHERE {
  ?elem tai:belongsTo <https://www.teamingai-project.eu/kg/process/qualityInspection/sid_628f8db4_6e66_4dbc_bf51_0a06087845fd> .
  ?elem a ?type .
  OPTIONAL { ?elem bbo:name ?elemName . }
  OPTIONAL { ?elem bboExt:loopType ?loopType . }
  OPTIONAL { ?elem bboExt:gatewayDirection ?gatewayDir . }
  FILTER(
    ?type IN (
      bboExt:ParallelGateway,
      bboExt:ExclusiveGateway,
      bboExt:EventBasedGateway,
      bboExt:ChoreographyTask
    )
  )
}
LIMIT 25
